// rch/tests/ui_integration.rs

mod support;
use support::*;

// ═══════════════════════════════════════════════════════════════
// CONTEXT DETECTION TESTS
// ═══════════════════════════════════════════════════════════════

mod context_tests {
    use super::*;
    use rch_common::ui::context::OutputContext;
    use serial_test::serial;

    #[test]
    #[serial] // Environment tests must be serial
    fn test_interactive_full_rich() {
        std::env::remove_var("NO_COLOR");
        std::env::remove_var("RCH_HOOK_MODE");
        std::env::remove_var("RCH_JSON");
        std::env::set_var("FORCE_COLOR", "1");

        let ctx = OutputContext::detect();
        assert!(ctx.supports_color());

        std::env::remove_var("FORCE_COLOR");
    }

    #[test]
    #[serial]
    fn test_hook_mode_no_output() {
        std::env::set_var("RCH_HOOK_MODE", "1");

        let ctx = OutputContext::detect();
        assert_eq!(ctx, OutputContext::Hook);
        assert!(ctx.is_machine());

        std::env::remove_var("RCH_HOOK_MODE");
    }

    #[test]
    #[serial]
    fn test_no_color_disables_all_formatting() {
        std::env::set_var("NO_COLOR", "1");
        std::env::set_var("FORCE_COLOR", "1"); // NO_COLOR should win

        let ctx = OutputContext::detect();
        assert!(!ctx.supports_color());

        std::env::remove_var("NO_COLOR");
        std::env::remove_var("FORCE_COLOR");
    }
}

// ═══════════════════════════════════════════════════════════════
// COMPONENT RENDERING TESTS  
// ═══════════════════════════════════════════════════════════════

mod component_tests {
    use super::*;

    #[test]
    fn test_status_table_rich() {
        let data = mock_status_data();
        let table = StatusTable::new(&data);
        let term = MockTerminal::new(80, 24);
        let output = table.render(&term);

        // Should have borders
        assert!(output.contains("┌") || output.contains("+"));
        // Should have data
        assert!(output.contains("worker1"));
        assert!(output.contains("127.0.0.1:9274"));
    }

    #[test]
    fn test_status_table_ascii_fallback() {
        let data = mock_status_data();
        let table = StatusTable::new(&data);
        let term = MockTerminal::new(80, 24).with_ascii_only();
        let output = table.render(&term);

        // Should use ASCII
        assert!(output.contains("+") || output.contains("-"));
        assert!(!output.contains("┌"));
    }

    #[test]
    fn test_worker_table_status_indicators() {
        let workers = mock_worker_data();
        let table = WorkerTable::new(&workers);
        let term = MockTerminal::new(100, 30);
        let output = table.render(&term);

        // Online should have green indicator
        // (Check for presence of status text)
        assert!(output.contains("Online") || output.contains("●"));
        assert!(output.contains("Offline") || output.contains("○"));
    }

    #[test]
    fn test_error_panel_structure() {
        let panel = ErrorPanel::new("RCH-E042", "Connection failed")
            .with_suggestion("Check SSH");
        let term = MockTerminal::new(80, 24);
        let output = panel.render(&term);

        assert!(output.contains("RCH-E042"));
        assert!(output.contains("Connection failed"));
        assert!(output.contains("Check SSH"));
    }
}

// ═══════════════════════════════════════════════════════════════
// SNAPSHOT TESTS
// ═══════════════════════════════════════════════════════════════

mod snapshot_tests {
    use super::*;

    #[test]
    fn snapshot_status_table_80col() {
        let data = mock_status_data();
        let table = StatusTable::new(&data);
        let output = table.render_to_string(80);
        assert_ui_snapshot!("status_table_80col", output);
    }

    #[test]
    fn snapshot_worker_table_100col() {
        let workers = mock_worker_data();
        let table = WorkerTable::new(&workers);
        let output = table.render_to_string(100);
        assert_ui_snapshot!("worker_table_100col", output);
    }

    #[test]
    fn snapshot_error_panel() {
        for (code, msg, suggestions) in mock_error_scenarios() {
            let mut panel = ErrorPanel::new(&code, &msg);
            for s in suggestions {
                panel = panel.with_suggestion(&s);
            }
            let output = panel.render_to_string(80);
            assert_ui_snapshot!(format!("error_{}", code), output);
        }
    }
}

// ═══════════════════════════════════════════════════════════════
// PERFORMANCE TESTS
// ═══════════════════════════════════════════════════════════════

mod performance_tests {
    use super::*;
    use std::time::Instant;

    #[test]
    fn test_render_overhead_under_5ms() {
        let data = mock_status_data();
        let workers = mock_worker_data();

        let start = Instant::now();
        for _ in 0..100 {
            let _ = StatusTable::new(&data).render_to_string(80);
            let _ = WorkerTable::new(&workers).render_to_string(100);
            let _ = ErrorPanel::new("E001", "Test").render_to_string(80);
        }
        let duration = start.elapsed();

        // 300 renders should take < 1500ms total (5ms each)
        assert!(duration.as_millis() < 1500, 
            "Rendering too slow: {:?} for 300 renders", duration);
    }
}
